          "content": "package com.state.before;\n\n/**\n * 1.\n * 电梯接口\n */\npublic interface ILift {\n    //定义四个电梯状态的常量\n    int OPENING_STATE = 1;\n    int CLOSING_STATE = 2;\n\n    int RUNNING_STATE = 3;\n\n    int STOPPING_STATE = 4;\n\n    //设置电梯状态的功能\n    void setState(int state);\n\n    void open();\n\n    void close();\n\n    void run();\n\n    void stop();\n\n\n}\n",
