          "name": "Lift.java",
          "path": "src/main/java/com/state/before/Lift.java",
          "package": "com.state.before",
          "content": "package com.state.before;\n\n/**\n * 2.\n * 电梯类（ILift的子实现类）\n */\npublic class Lift implements ILift{\n\n    //声明一个记录当前电梯状态的一个变量\n    private int state;\n    @Override\n    public void setState(int state) {\n        this.state = state;\n    }\n\n    @Override\n    public void open() {\n        switch (state) {//当前电梯状态\n            case OPENING_STATE:\n                //什么事都不做\n                break;\n            case CLOSING_STATE:\n                System.out.println(\"电梯打开了。。。\");\n                //设置当前电梯状态为开启\n                setState(OPENING_STATE);\n                break;\n            case RUNNING_STATE:\n                //什么事都不做\n                break;\n            case STOPPING_STATE:\n                System.out.println(\"电梯打开了。。。\");\n                //设置当前电梯状态为开启\n                setState(OPENING_STATE);\n                break;\n        }\n    }\n\n    @Override\n    public void close() {\n        switch (state) {//当前电梯状态\n            case OPENING_STATE:\n                System.out.println(\"电梯关闭了。。。\");\n                //设置当前电梯状态为关闭\n                setState(CLOSING_STATE);\n                break;\n            case CLOSING_STATE:\n                //什么事都不做\n                break;\n            case RUNNING_STATE:\n                //运行时电梯门是关着的 不能关门\n                break;\n            case STOPPING_STATE:\n                //什么事都不做\n                break;\n        }\n    }\n\n    @Override\n    public void run() {\n        switch (state) {//当前电梯状态\n            case OPENING_STATE:\n                //电梯开着门不能走\n                break;\n            case CLOSING_STATE:\n                System.out.println(\"电梯开始运行了。。。\");\n                //设置当前电梯状态为运行\n                setState(RUNNING_STATE);\n                break;\n            case RUNNING_STATE:\n                //已经是运行中了\n                break;\n            case STOPPING_STATE:\n                System.out.println(\"电梯开始运行了。。。\");\n                //设置当前电梯状态为运行\n                setState(RUNNING_STATE);\n                break;\n        }\n    }\n\n    @Override\n    public void stop() {\n        switch (state) {//当前电梯状态\n            case OPENING_STATE:\n                //电梯开着门一般就是停止状态了\n                break;\n            case CLOSING_STATE:\n                System.out.println(\"电梯停止了。。。\");\n                //设置当前电梯状态为停止\n                setState(STOPPING_STATE);\n                break;\n            case RUNNING_STATE:\n                System.out.println(\"电梯停止了。。。\");\n                setState(STOPPING_STATE);\n                break;\n            case STOPPING_STATE:\n                break;\n        }\n    }\n}\n",
